import { Inject, Injectable, Logger } from '@nestjs/common';
import { HealthIndicatorResult, HealthIndicatorService } from '@nestjs/terminus';
import { Knex } from 'knex';

import { bufferedRollbar } from '@config/rollbar-buffer.config';

import { CacheService } from '@modules/cache/cache.service';

import { KNEX_READ_CONNECTION } from '@constants/db.constant';

import { Namespaces } from '@interfaces/cache.interface';

@Injectable()
export class HealthService {
	private readonly logger = new Logger(HealthService.name);

	constructor(
		@Inject(HealthIndicatorService)
		private readonly healthIndicatorService: HealthIndicatorService,
		@Inject() private readonly cacheService: CacheService,
		@Inject(KNEX_READ_CONNECTION) private readonly knexRead: Knex,
	) {}

	async isAPIHealthy({
		key,
	}: {
		key: string;
	}): Promise<
		| HealthIndicatorResult<
				string,
				'up',
				{ message: string; timestamp: number; uptime: number }
		  >
		| HealthIndicatorResult<string, 'down', { message: string; error: string }>
	> {
		try {
			this.logger.log(`Checking health of ${key}`);
			await fetch(key);

			return this.healthIndicatorService.check(key).up({
				message: 'API is working',
				timestamp: Date.now(),
				uptime: process.uptime(),
			});
		} catch (error) {
			this.logger.error(`Health check failed for ${key}`, JSON.stringify(error));
			bufferedRollbar.error({ err: error as Error });
			return this.healthIndicatorService.check(key).down({
				message: 'API is not responding',
				error: (error as Error).message,
			});
		}
	}

	async isRedisHealthy(): Promise<
		| HealthIndicatorResult<string, 'up', { message: string; latency: number }>
		| HealthIndicatorResult<string, 'down', { message: string; error: string }>
	> {
		try {
			this.logger.log('Checking Redis health');
			const start = Date.now();

			const testKey = 'health-check';
			const testValue = Date.now().toString();

			await this.cacheService.set({
				namespace: Namespaces.HEALTH_CHECK,
				key: testKey,
				value: testValue,
				ttl: 2000,
			});

			const retrievedValue = await this.cacheService.get<string>({
				namespace: Namespaces.HEALTH_CHECK,
				key: testKey,
			});

			if (retrievedValue !== testValue) {
				throw new Error('Redis data integrity check failed');
			}

			const latency = Date.now() - start;

			return this.healthIndicatorService.check('redis').up({
				message: 'Redis is working',
				latency,
			});
		} catch (error) {
			this.logger.error('Redis health check failed', JSON.stringify(error));
			bufferedRollbar.error({ err: error as Error });
			return this.healthIndicatorService.check('redis').down({
				message: 'Redis is not responding',
				error: (error as Error).message,
			});
		}
	}

	async isDatabaseHealthy(): Promise<
		| HealthIndicatorResult<string, 'up', { message: string; latency: number }>
		| HealthIndicatorResult<string, 'down', { message: string; error: string }>
	> {
		try {
			this.logger.log('Checking database health');
			const start = Date.now();

			await this.knexRead.raw('SELECT 1 as health_check');

			const latency = Date.now() - start;

			return this.healthIndicatorService.check('database').up({
				message: 'Database is working',
				latency,
			});
		} catch (error) {
			this.logger.error('Database health check failed', JSON.stringify(error));
			bufferedRollbar.error({ err: error as Error });
			return this.healthIndicatorService.check('database').down({
				message: 'Database is not responding',
				error: (error as Error).message,
			});
		}
	}
}

