import { Controller, Get, HttpStatus, Logger } from '@nestjs/common';
import { ApiOkResponse, ApiOperation, ApiResponse, ApiTags } from '@nestjs/swagger';
import {
	HealthCheckService,
	DiskHealthIndicator,
	MemoryHealthIndicator,
	HealthCheck,
	HealthCheckResult,
} from '@nestjs/terminus';

import { HealthService } from '@modules/health/health.service';

let isSIGTERM = false;
process.on('SIGTERM', () => {
	isSIGTERM = true;
});

@ApiTags('Health')
@Controller()
export class HealthController {
	private readonly logger = new Logger(HealthController.name);

	constructor(
		private health: HealthCheckService,
		private disk: DiskHealthIndicator,
		private memory: MemoryHealthIndicator,
		private healthService: HealthService,
	) {}

	@ApiOperation({ summary: 'Health Check status.' })
	@HealthCheck({ swaggerDocumentation: false })
	@ApiOkResponse({
		description: 'Health check status',
		schema: {
			type: 'object',
			properties: { status: { type: 'string', enum: ['up'] } },
		},
	})
	@ApiResponse({ status: 503, description: 'Service is down' })
	@Get('is_it_up')
	isItUp(): { status: 'up' } {
		return { status: 'up' };
	}

	@ApiOperation({ summary: 'Working Check status.' })
	@ApiResponse({
		status: HttpStatus.OK,
		description: 'Return status 200 if the application is ready to serve traffic',
	})
	@HealthCheck()
	@Get('is_it_working')
	async isItWorking(): Promise<HealthCheckResult> {
		if (isSIGTERM) {
			return {
				status: 'shutting_down',
				info: {},
				error: {},
				details: {},
			};
		}

		this.logger.log('Checking application readiness');

		return await this.health.check([
			() => this.healthService.isAPIHealthy({ key: 'https://docs.nestjs.com' }),
			() => this.healthService.isRedisHealthy(),
			() => this.healthService.isDatabaseHealthy(),
			() => this.memory.checkHeap('memory_heap', 500 * 1024 * 1024),
			() => this.disk.checkStorage('storage', { path: '/', thresholdPercent: 0.77 }),
		]);
	}
}
